INSERT INTO recipe_steps (recipe_id, step_number, instruction, tip) VALUES
(1, 1, 'Wash those spuds! Scrub potatoes under cold water. Kids love using the veggie brush!', 'Get the grown-up veggie brush - it makes scrubbing fun!'),
(1, 2, 'Grate time! Ask a grown-up to help you grate the potatoes. Watch your fingers!', 'Keep fingers curled under and use the guard if you have one.'),
(1, 3, 'Squeeze party! Put grated potatoes in a clean towel and squeeze out the water. This is the fun part - make a potato water balloon!', 'Squeeze as hard as you can! The drier the potatoes, the crispier they get.'),
(1, 4, 'Heat it up! Ask a grown-up to heat oil in a big pan over medium heat.', 'The oil should shimmer but not smoke - that means it is ready!'),
(1, 5, 'Spud spread! Spread potatoes in the pan and press down gently. Listen for the sizzle!', 'Spread them in an even layer - no potato piles allowed!'),
(1, 6, 'Season sprinkle! Sprinkle salt, pepper, and garlic powder on top.', 'Hold your hand high when sprinkling for even coverage.'),
(1, 7, 'Patience test! Cook for 5-7 minutes without touching. Good things take time!', 'Resist the urge to flip early - they need time to get crispy!'),
(1, 8, 'Flip trick! Ask a grown-up to flip the hash browns so both sides get crispy.', 'Use a big spatula and flip with confidence!'),
(1, 9, 'Golden goal! Cook until golden brown and crunchy. Dip in ketchup and enjoy!', 'They should be deep golden and make a crunch sound when you tap them.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction, tip) VALUES
(2, 1, 'Cube crew! Cut sweet potatoes into small cubes - think dice size!', 'Try to make all cubes the same size so they cook evenly.'),
(2, 2, 'Veggie prep! Dice the red pepper and onion. Make them small pieces.', 'Small pieces cook faster and fit better on your fork!'),
(2, 3, 'Hot pan ready! Ask a grown-up to heat oil in a big skillet.', 'Medium heat is perfect - hot enough to cook, not hot enough to burn.'),
(2, 4, 'Sweet spuds first! Cook sweet potatoes for 8-10 minutes, stirring sometimes.', 'They take the longest, so they go in first. Stir so they do not stick.'),
(2, 5, 'Add the colors! Toss in peppers and onions. Watch the rainbow happen!', 'The colors make this dish beautiful AND tasty!'),
(2, 6, 'Spice it up! Sprinkle paprika and salt over everything.', 'Paprika gives a smoky flavor and pretty color.'),
(2, 7, 'Make little nests! Use a spoon to make 4 small holes in the hash.', 'These nests will hold our eggs - like cozy egg beds!'),
(2, 8, 'Egg drop! Crack an egg into each hole. This is the cool part!', 'Crack on a flat surface, not the edge of the bowl - less shell mess!'),
(2, 9, 'Cover up! Put a lid on the pan and cook until eggs are done how you like.', 'Runny yolks = 3-4 minutes. Firm yolks = 5-6 minutes.'),
(2, 10, 'Garnish game! Sprinkle parsley on top. You are a chef now!', 'Fresh herbs make any dish look fancy and taste fresh.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction, tip) VALUES
(3, 1, 'Grate team! Grate potatoes and onion. Watch those fingers!', 'Use the big holes on your grater. Go fast but be safe!'),
(3, 2, 'Squeeze squad! Squeeze out all the water from the potatoes. Really squeeze!', 'Use a clean kitchen towel. Twist it tight like a candy wrapper!'),
(3, 3, 'Mix master! In a big bowl, mix potatoes, onion, eggs, flour, salt, and baking powder.', 'Get your hands in there and mix it all together!'),
(3, 4, 'Stir it up! Mix until everything is combined. It looks funny but that is okay!', 'The mixture will look gray and weird - that is normal!'),
(3, 5, 'Oil ready! Ask a grown-up to heat oil in a pan - about 1/4 inch deep.', 'The oil should be hot but not smoking. Test with a tiny drop of batter.'),
(3, 6, 'Scoop and drop! Use a spoon to drop small mounds into the hot oil. Flatten slightly.', 'Do not make them too big - think cookie size!'),
(3, 7, 'Sizzle watch! Cook for 3-4 minutes until the bottom is golden brown.', 'You will see golden edges peeking up when it is time to flip.'),
(3, 8, 'Flip carefully! Turn them over with a spatula. Watch out for hot oil!', 'Gentle flips only - they are delicate little pancakes!'),
(3, 9, 'Paper towel bed! Put cooked latkes on paper towels to drain extra oil.', 'Give them a minute to drain - soggy latkes are no fun!'),
(3, 10, 'Dip party! Serve warm with applesauce or sour cream. Which one do you like?', 'Try both! Some people like sweet, some like tangy.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction, tip) VALUES
(4, 1, 'Scrub-a-dub! Wash the potato really well. We are eating the skin too!', 'Use a brush and get all the dirt off the skin.'),
(4, 2, 'Poke party! Use a fork to poke holes all over the potato. This lets steam escape.', '8-10 pokes all over - this keeps the potato from exploding!'),
(4, 3, 'Microwave magic! Cook in microwave for 5 minutes to soften it up.', 'Put it on a microwave-safe plate - it might drip.'),
(4, 4, 'Oven time! Rub potato with butter and put in oven at 400°F for 45 minutes.', 'The butter makes the skin crispy and yummy!'),
(4, 5, 'Bacon crunch! While potato bakes, ask a grown-up to help cook the bacon until crispy.', 'Cook until it is brown and crunchy. Watch it so it does not burn!'),
(4, 6, 'Egg scramble! Scramble the eggs in a pan until fluffy.', 'Stir constantly for soft, fluffy eggs. Do not let them get brown.'),
(4, 7, 'Split it! Cut a slit down the middle of the baked potato. Be careful - it is hot!', 'Make a deep X shape and squeeze the ends to open it up.'),
(4, 8, 'Fluff master! Use a fork to fluff up the insides. Make room for toppings!', 'Fluff it good - you want space for all the yummy stuff!'),
(4, 9, 'Load it up! Stuff potato with eggs, crumbled bacon, and cheese.', 'Pack it full! The more toppings, the better!'),
(4, 10, 'Melt moment! Put back in oven for 2-3 minutes to melt the cheese.', 'Watch it - as soon as the cheese melts, it is ready!'),
(4, 11, 'Top it off! Add chives and dig in. Breakfast in a potato!', 'This is a whole meal in one potato. How cool is that?');
INSERT INTO recipe_steps (recipe_id, step_number, instruction, tip) VALUES
(5, 1, 'Dice dice baby! Cut potatoes into small cubes - about the size of your thumbnail.', 'Keep all pieces the same size so they cook evenly.'),
(5, 2, 'Pan party! Melt butter in a big skillet over medium heat.', 'Swirl the pan to coat the bottom with melted butter.'),
(5, 3, 'Potato power! Cook potatoes for 10-12 minutes until they are soft and golden.', 'Stir every few minutes so they do not stick or burn.'),
(5, 4, 'Crack attack! In a bowl, whisk the eggs with a fork until they are yellow.', 'Beat them well - no streaks of white should remain.'),
(5, 5, 'Pour and stir! Pour eggs over the potatoes and stir gently.', 'Keep stirring so the eggs cook evenly and stay soft.'),
(5, 6, 'Cheese please! Sprinkle cheese over the egg and potato mixture.', 'Any cheese works - cheddar, Monterey Jack, or a mix!'),
(5, 7, 'Soft scramble! Cook until eggs are soft and cheese is melty.', 'Do not overcook - soft eggs are creamier and tastier!'),
(5, 8, 'Tortilla time! Warm tortillas in microwave for 15 seconds.', 'Warm tortillas bend without breaking. Cold ones crack!'),
(5, 9, 'Stuff it! Spoon filling onto each tortilla. Do not overfill!', 'Leave space at the edges so you can roll it up.'),
(5, 10, 'Roll it up! Fold in sides and roll up like a sleeping bag.', 'Roll tight so nothing falls out when you eat it!'),
(5, 11, 'Grab and go! Wrap in foil if taking to school. Enjoy with salsa!', 'Foil keeps them warm and makes them easy to hold.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction, tip) VALUES
(6, 1, 'Scrub scrub! Wash sweet potatoes well. No dirt allowed!', 'These skins are edible, so wash them really good!'),
(6, 2, 'Slice machine! Ask a grown-up to cut sweet potatoes into thin slices - about 1/4 inch.', 'The slices should be thin but not see-through.'),
(6, 3, 'Oil brush! Brush both sides with olive oil. Use a pastry brush!', 'A light coating is all you need - not swimming in oil!'),
(6, 4, 'Salt sprinkle! Sprinkle a tiny bit of salt on each slice.', 'A pinch per slice makes them taste even better.'),
(6, 5, 'Sheet ready! Put slices on a baking sheet. No overlapping!', 'Give them space so they can cook evenly all around.'),
(6, 6, 'Oven adventure! Bake at 400°F for 20-25 minutes, flipping halfway.', 'Flip them at 10 minutes so both sides get crispy.'),
(6, 7, 'Toast test! They are done when they are soft inside and a little crispy outside.', 'Poke with a fork - it should go through easily.'),
(6, 8, 'Cool down! Let them cool for a few minutes.', 'They are hot right out of the oven!'),
(6, 9, 'Top it! Spread on your favorite topping. Get creative!', 'Try peanut butter and banana, or cream cheese and berries!'),
(6, 10, 'Eat the rainbow! Sweet potato toast is colorful and yummy!', 'This is a healthy alternative to bread - and more fun!');
INSERT INTO recipe_steps (recipe_id, step_number, instruction, tip) VALUES
(7, 1, 'Preheat power! Turn oven to 350°F. Ask a grown-up for help!', 'Always preheat so the oven is hot when the food goes in.'),
(7, 2, 'Pan prep! Spray a 9x13 baking dish with cooking spray.', 'Greasing the pan keeps the casserole from sticking.'),
(7, 3, 'Spud spread! Spread hash browns in the bottom of the dish.', 'Spread them in an even layer across the whole bottom.'),
(7, 4, 'Ham scatter! Sprinkle diced ham all over the potatoes.', 'Spread it out so every bite has some ham.'),
(7, 5, 'Cheese rain! Sprinkle half the cheese on top. Cheese rain is the best rain!', 'Watch it snow cheese over the casserole!'),
(7, 6, 'Egg mix! In a bowl, whisk eggs, milk, salt, and pepper together.', 'Whisk until it is all one color - no streaks.'),
(7, 7, 'Pour party! Pour egg mixture evenly over everything.', 'Pour slowly so it seeps into all the corners.'),
(7, 8, 'More cheese! Sprinkle remaining cheese on top.', 'This will make a golden cheesy crust on top!'),
(7, 9, 'Bake time! Put in oven for 45 minutes until eggs are set.', 'It should not jiggle when you shake the pan gently.'),
(7, 10, 'Golden goal! Look for golden cheese on top. That is when it is done!', 'The top should be bubbly and lightly browned.'),
(7, 11, 'Cut and serve! Let cool 5 minutes, then cut into squares.', 'Letting it rest makes it easier to cut and serve.');
INSERT INTO recipe_steps (recipe_id, step_number, instruction, tip) VALUES
(8, 1, 'Cube crew! Cut potatoes into bite-sized cubes. Keep them similar sizes!', 'Think dice size - about half an inch on each side.'),
(8, 2, 'Pepper party! Dice the red and green peppers into small pieces.', 'Cut them the same size as the potatoes so they cook evenly.'),
(8, 3, 'Oil ready! Ask a grown-up to heat oil in a big skillet.', 'Use enough oil to coat the bottom of the pan.'),
(8, 4, 'Potatoes first! Add potatoes to the pan. Spread them out!', 'Do not pile them up - spread them in a single layer.'),
(8, 5, 'Sizzle time! Cook for 10 minutes, stirring every few minutes.', 'They are getting crispy and golden!'),
(8, 6, 'Add the colors! Toss in the peppers. Watch the rainbow!', 'The peppers add color and a sweet crunch.'),
(8, 7, 'Spice sprinkle! Add salt, paprika, and garlic powder.', 'Paprika gives them a nice orange-red color!'),
(8, 8, 'Keep cooking! Cook for another 10-15 minutes until crispy.', 'They should be crunchy on the outside, soft inside.'),
(8, 9, 'Golden test! Potatoes should be golden outside and soft inside.', 'Test one - it should break easily with a fork.'),
(8, 10, 'Dip and eat! Try with ketchup or hot sauce (if you like spicy).', 'These are like fancy home fries from a diner!');
INSERT INTO recipe_steps (recipe_id, step_number, instruction, tip) VALUES
(9, 1, 'Grate great! Grate potatoes and onion. Watch those fingers!', 'Grate straight down - do not slide along the grater.'),
(9, 2, 'Squeeze squad! Squeeze out all the potato water. Use a towel!', 'The drier the potatoes, the crispier the waffles!'),
(9, 3, 'Mix it up! Combine potatoes, onion, eggs, flour, salt, and pepper in a bowl.', 'Use your hands - it is the best way to mix it all!'),
(9, 4, 'Waffle iron ready! Heat up the waffle iron and spray with cooking spray.', 'Make sure it is hot before you add the batter.'),
(9, 5, 'Scoop and spread! Put a big scoop of mixture in the waffle iron. Spread it out.', 'Fill it about 3/4 full - it will spread when you close it.'),
(9, 6, 'Close it! Shut the lid and press down gently. Listen for the sizzle!', 'Do not press too hard - let the waffle iron do the work.'),
(9, 7, 'Wait game! Cook for 5-7 minutes. Do not peek too early!', 'Resist the urge to open it early - they need time to crisp.'),
(9, 8, 'Golden check! Open carefully. They should be crispy and golden.', 'If they are pale, close it and cook another minute.'),
(9, 9, 'Remove gently! Use a fork to lift out. They are delicate!', 'Be gentle - they can fall apart if you are rough.'),
(9, 10, 'Repeat! Make more waffles until mixture is gone.', 'Keep the iron sprayed so they do not stick.'),
(9, 11, 'Dip and eat! Serve hot with sour cream. Waffle shapes are fun!', 'The little squares hold the sour cream perfectly!');
INSERT INTO recipe_steps (recipe_id, step_number, instruction, tip) VALUES
(10, 1, 'Prep work! Cube potatoes, slice sausage, dice onion.', 'Do all your cutting first - it makes cooking easier!'),
(10, 2, 'Pan hot! Melt butter in a big skillet over medium-high heat.', 'The butter adds flavor and keeps things from sticking.'),
(10, 3, 'Potatoes in! Add potatoes first - they take longest. Cook 10 minutes.', 'Stir them so they get crispy on all sides.'),
(10, 4, 'Sausage time! Add sausage slices. Cook until browned.', 'Sausage adds a yummy savory flavor.'),
(10, 5, 'Onion addition! Toss in onions. Cook until soft.', 'Onions get sweet and soft when they cook.'),
(10, 6, 'Make nests! Use a spoon to make 4 holes in the mixture.', 'These holes are for the eggs to nest in.'),
(10, 7, 'Egg crack! Crack an egg into each hole. Be gentle!', 'Crack on a flat surface to avoid shells in the food.'),
(10, 8, 'Cover up! Put a lid on and cook until eggs are how you like.', 'Runny yolks take about 3 minutes. Firm takes 5-6.'),
(10, 9, 'Cheese it! Sprinkle cheese over everything. Let it melt.', 'Watch it melt - it only takes a minute!'),
(10, 10, 'Season! Add salt and pepper to taste.', 'Taste first - sausage is already salty!'),
(10, 11, 'Garnish! Sprinkle parsley. It is pretty AND tasty!', 'This looks like a restaurant breakfast!');
INSERT INTO recipe_steps (recipe_id, step_number, instruction, tip) VALUES
(11, 1, 'Dice dice! Cut potatoes into small cubes.', 'Small cubes cook faster and mix well with eggs.'),
(11, 2, 'Veggie prep! Cut tomatoes in half and chop spinach.', 'Tomatoes add sweetness, spinach adds color!'),
(11, 3, 'Butter melt! Melt butter in a pan over medium heat.', 'Swirl it around to coat the whole bottom.'),
(11, 4, 'Potato start! Cook potatoes for 8-10 minutes until soft.', 'Stir them so they do not stick or burn.'),
(11, 5, 'Crack eggs! Whisk eggs in a bowl with a fork.', 'Beat them until they are all yellow.'),
(11, 6, 'Pour and scramble! Pour eggs into the pan and stir gently.', 'Keep stirring for soft, fluffy eggs!'),
(11, 7, 'Add colors! When eggs are half-cooked, add tomatoes and spinach.', 'Add them late so they do not get mushy.'),
(11, 8, 'Keep stirring! Cook until eggs are fluffy and veggies are warm.', 'The spinach will wilt and the tomatoes will warm.'),
(11, 9, 'Season! Sprinkle with salt and pepper.', 'A little salt makes everything taste better.'),
(11, 10, 'Eat the rainbow! Look at all those pretty colors on your plate!', 'This is a healthy, colorful breakfast!');
INSERT INTO recipe_steps (recipe_id, step_number, instruction, tip) VALUES
(12, 1, 'Preheat! Set oven to 350°F.', 'Oven needs to be hot when muffins go in.'),
(12, 2, 'Sweet spud prep! Cook and mash sweet potatoes. Let them cool.', 'You can use leftover mashed sweet potatoes too!'),
(12, 3, 'Bowl one! In a big bowl, mix flour, baking powder, baking soda, salt, and cinnamon.', 'Mix the dry ingredients first so they are evenly spread.'),
(12, 4, 'Bowl two! In another bowl, mix sweet potato, sugar, eggs, and oil.', 'Mix until it is smooth and well combined.'),
(12, 5, 'Combine! Pour wet ingredients into dry ingredients. Stir until just mixed.', 'Do not overmix! Lumps are okay - they make muffins fluffy.'),
(12, 6, 'Chocolate chips! Fold in chocolate chips if using.', 'Save some to put on top for pretty muffins!'),
(12, 7, 'Muffin tin! Put paper liners in muffin tin or spray with oil.', 'Liners make cleanup easy!'),
(12, 8, 'Scoop! Fill each muffin cup 3/4 full.', 'They will rise, so do not fill them all the way.'),
(12, 9, 'Bake! Put in oven for 18-20 minutes.', 'Set a timer so you do not forget!'),
(12, 10, 'Toothpick test! Stick a toothpick in - if it comes out clean, they are done!', 'If there is batter on the toothpick, bake 2 more minutes.'),
(12, 11, 'Cool! Wait 5 minutes before eating. Hard but worth it!', 'Hot muffins can burn your tongue!');
